+    /// IMPL-9a: verify the QuotientFilter short-circuits direct-simple
+    /// DELETE lookups for rowids that are provably absent from the
+    /// committed B-tree. We insert 100 rowids in range `[0, 100)` and
+    /// then DELETE 100 distinct rowids in range `[10_000, 10_100)`
+    /// that are definitely not present. Every such DELETE must be
+    /// classified as absent by the filter. The first consult pays for
+    /// the one-shot build scan, so we allow a small slack — we just
+    /// require that the filter short-circuits ≥ 90 / 100.
+    #[test]
+    fn test_quotient_filter_short_circuits_absent_rowids_on_delete() {
+        let conn = Connection::open(":memory:").unwrap();
+        conn.execute("CREATE TABLE qf_absent (id INTEGER PRIMARY KEY, val INTEGER NOT NULL);")
+            .unwrap();
+        conn.execute("BEGIN").unwrap();
+        let ins = conn
+            .prepare("INSERT INTO qf_absent VALUES (?1, ?1)")
+            .unwrap();
+        for i in 0..100i64 {
+            ins.execute_with_params(&[SqliteValue::Integer(i)]).unwrap();
+        }
+        conn.execute("COMMIT").unwrap();
+
+        // Reset the short-circuit counter so the INSERT-side maintenance
+        // path (which never consults) can't inflate the count.
+        conn.reset_quotient_filter_short_circuit_count();
+
+        // Direct-simple DELETE is gated on explicit txn state. Wrap the
+        // 100 phantom DELETEs in a single BEGIN/COMMIT so every one
+        // takes the direct fast path (the VDBE fallback doesn't consult
+        // the QF).
+        conn.execute("BEGIN").unwrap();
+        let del = conn.prepare("DELETE FROM qf_absent WHERE id = ?1").unwrap();
+        for i in 10_000..10_100i64 {
+            let affected = del.execute_with_params(&[SqliteValue::Integer(i)]).unwrap();
+            assert_eq!(affected, 0, "absent rowid {i} cannot delete any rows");
+        }
+        conn.execute("COMMIT").unwrap();
+
+        let short_circuits = conn.quotient_filter_short_circuit_count();
+        assert!(
+            short_circuits >= 90,
+            "expected ≥ 90 QF short-circuits, got {short_circuits} (filter build-scan reserves some slack)"
+        );
+
+        // Row count unaffected by the phantom DELETEs.
+        let rows = conn.query("SELECT COUNT(*) FROM qf_absent").unwrap();
+        assert_eq!(rows[0].values()[0], SqliteValue::Integer(100));
+    }
+
+    /// IMPL-9a: INSERT + DELETE of the same rowid must leave the filter
+    /// in a state where a subsequent DELETE of the same rowid short-
+    /// circuits (the row is definitely absent). Validates the
+    /// `qf_record_delete` maintenance path.
+    #[test]
+    fn test_quotient_filter_delete_then_redelete_short_circuits() {
+        let conn = Connection::open(":memory:").unwrap();
+        conn.execute("CREATE TABLE qf_del (id INTEGER PRIMARY KEY, val INTEGER NOT NULL);")
+            .unwrap();
+        // Seed the table and commit so the filter has committed state
+        // to build from.
+        conn.execute("INSERT INTO qf_del VALUES (42, 42);").unwrap();
+
+        // Direct-simple DELETE requires an explicit transaction.
+        conn.execute("BEGIN").unwrap();
+        let del = conn.prepare("DELETE FROM qf_del WHERE id = ?1").unwrap();
+        // First DELETE: filter builds on first consult, then removes 42.
+        let affected = del
+            .execute_with_params(&[SqliteValue::Integer(42)])
+            .unwrap();
+        assert_eq!(affected, 1, "first DELETE should remove the row");
+
+        conn.reset_quotient_filter_short_circuit_count();
+
+        // Second DELETE of the same rowid: filter knows it's gone.
+        let affected = del
+            .execute_with_params(&[SqliteValue::Integer(42)])
+            .unwrap();
+        assert_eq!(affected, 0, "row is already gone; nothing to delete");
+        assert!(
+            conn.quotient_filter_short_circuit_count() >= 1,
+            "second DELETE of a removed rowid must short-circuit via the QF"
+        );
+        conn.execute("COMMIT").unwrap();
+    }
+
+    /// IMPL-9a (critical correctness): INSERT under a transaction,
+    /// ROLLBACK the transaction, then DELETE the same rowid. The
+    /// rollback must force the filter to forget the never-committed
+    /// INSERT. Because the row is absent in committed state (and was
+    /// never there), the DELETE still returns 0 — but crucially, the
+    /// DELETE must NOT be short-circuited with a stale "present"
+    /// verdict AND must NOT be short-circuited with a stale "absent"
+    /// verdict that bypasses the descent before reseeding. The
+    /// strongest observable invariant is that the rollback path resets
+    /// `built=false`, so the next consult reseeds from the post-
+    /// rollback committed B-tree (which may be empty — trivially
+    /// seeded).
+    #[test]
+    fn test_quotient_filter_rollback_forces_reseed() {
+        let conn = Connection::open(":memory:").unwrap();
+        conn.execute("CREATE TABLE qf_rb (id INTEGER PRIMARY KEY, val INTEGER NOT NULL);")
+            .unwrap();
+
+        // Seed the filter by running a DELETE that misses (triggers a
+        // build scan on the empty table — filter now has built=true,
+        // zero fingerprints).
+        let del = conn.prepare("DELETE FROM qf_rb WHERE id = ?1").unwrap();
+        del.execute_with_params(&[SqliteValue::Integer(999)])
+            .unwrap();
+
+        // Start a transaction and INSERT rowid=7. Under our maintenance
+        // path, the filter now claims 7 is "maybe present".
+        conn.execute("BEGIN").unwrap();
+        let ins = conn.prepare("INSERT INTO qf_rb VALUES (?1, ?1)").unwrap();
+        ins.execute_with_params(&[SqliteValue::Integer(7)]).unwrap();
+
+        // Rollback — discard the insert. The filter's "7 is present"
+        // claim must be invalidated or the subsequent DELETE would
+        // descend and find nothing (safe), but the invariant we test
+        // is stronger: the filter is actually reseeded.
+        conn.execute("ROLLBACK").unwrap();
+
+        // Peek at the filter state directly — the rollback must have
+        // reset the entry's `built` flag.
+        {
+            let filters = conn.quotient_filters.borrow();
+            // The filter entry for this table may exist (created by the
+            // first DELETE consultation) — whichever entry exists must
+            // not carry a committed-but-rolled-back mutation forward.
+            // Specifically, `modified_in_txn` must be cleared.
+            for entry in filters.values() {
+                assert!(
+                    !entry.modified_in_txn,
+                    "rollback must clear modified_in_txn on every filter entry"
+                );
+            }
+        }
+
+        conn.reset_quotient_filter_short_circuit_count();
+
+        // DELETE rowid=7 post-rollback. Row is absent in committed
+        // state. Two outcomes are acceptable:
+        //   (a) the filter was reseeded (built=false → reseed → built=
+        //       true with no fingerprints) → short-circuit count += 1.
+        //   (b) the filter simply forgot the insert → short-circuit
+        //       still fires after contains()=false.
+        // Both outcomes must yield `affected == 0` and must not
+        // corrupt the committed B-tree.
+        let affected = del.execute_with_params(&[SqliteValue::Integer(7)]).unwrap();
+        assert_eq!(
+            affected, 0,
+            "post-rollback DELETE of the never-committed rowid must affect 0 rows"
+        );
+
+        // Committed row count is zero (INSERT was rolled back).
+        let rows = conn.query("SELECT COUNT(*) FROM qf_rb").unwrap();
+        assert_eq!(rows[0].values()[0], SqliteValue::Integer(0));
+    }
+
